VALUES
  ('judicial-57f41407-moex-00263', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '當事人就一般民事訴訟事件成立訴訟上和解時，原告得於成立之日起3個月內聲請退還其於該審級所 繳裁判費之比例為何？', '["全部", "三分之二", "二分之一", "四分之三"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00264', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲主張乙不依兩造間買賣契約移轉A地所有權，且意圖出售予第三人，聲請裁定准予假處分，禁止乙 處分 A 地。經第一審及抗告法院分別駁回其聲請及抗告後，甲不服，提起再抗告。下列敘述何者正 確？', '["再抗告程序未規定應委任律師為訴訟代理人，甲提起再抗告，無須委任律師為訴訟代理人", "再抗告程序非上訴第三審程序，A地之市價縱未逾新臺幣150萬元，仍得再抗告", "抗告法院之裁定如漏未斟酌乙是否意圖出售 A 地之事實，僅生裁定不備理由之問題，甲不得以此 為由提起再抗告", "甲提起再抗告時，應以抗告法院所為裁定適用法規之法律上判斷顯有錯誤為限，並須經抗告法院之 許可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00265', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於再審之訴，下列敘述何者正確？', '["再審之訴，應於20日之不變期間內提出", "當事人未經合法代理不得作為再審事由", "判決理由與主文顯有矛盾可作為再審事由", "適用法規顯有錯誤不得作為再審事由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00266', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者，非屬保全程序？', '["假執行", "假扣押", "假處分", "定暫時狀態處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00267', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '有法律上利害關係之甲，對於確定判決提起第三人撤銷訴訟時，關於對何法院所為之判決起訴及定管 轄法院，下列敘述何者錯誤？', '["於第一審判決後，經第二審法院以上訴不合法駁回上訴而確定之情形，專屬原第一審法院管轄", "於第一審判決後，經第二審法院以上訴有理由廢棄原判決並自為變更之判決而確定之情形，甲不得 對於該第一審判決起訴", "於第二審判決後，經第三審法院以上訴無理由駁回上訴而確定之情形，甲對於歷審判決合併起訴者， 專屬原第三審法院管轄", "於第一審與第二審法院均為本案判決而確定後，甲對於歷審判決合併起訴者，專屬原第二審法院管轄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00268', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於通常訴訟程序之起訴，下列敘述何者錯誤？', '["確認法律關係之訴，非被告有即受確認判決之法律上利益者，不得提起之", "起訴，應以訴狀表明當事人、訴訟標的及其原因事實以及應受判決事項之聲明", "原告之訴，依其所訴之事實，在法律上顯無理由者，法院得不經言詞辯論，逕以判決駁回之", "當事人不得就已起訴之事件，於訴訟繫屬中，更行起訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00269', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列家事非訟事件中，何者非法院得依職權開啟程序之事件？', '["認可收養未成年子女", "定對於未成年子女權利義務之行使或負擔", "停止親權", "定父或母與未成年子女間之會面交往方式及期間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00270', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於扶養費、家庭生活費用或贍養費等金錢請求之給付方法及執行，下列敘述何者錯誤？', '["法院定給付方法時，得審酌一切情況定之，惟基於處分權主義，仍受聲請人聲明之拘束", "法院定給付方法時，得依聲請或依職權，命為一次給付、分期給付或給付定期金，必要時並得命提 出擔保", "債務人依執行名義應定期給付費用，而有一期未完全履行時，債權人就其餘履行期尚未屆至之部分， 亦得聲請執行", "於執行扶養費請求權時，暫免繳裁判費，而由執行所得扣還之 乙、刑事訴訟法部分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00271', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於刑事訴訟不告不理原則，下列敘述何者正確？', '["係指告訴乃論之罪，未經告訴，即不能起訴", "係指告訴乃論之罪，未經告訴，即不能偵查", "係指未經檢察官或自訴人起訴之犯罪，法官不能審判", "係指檢察官就犯罪事實一部起訴者，其效力不及於全部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00272', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者為現行刑事訴訟法採行改良式當事人進行主義的特徵？', '["交互詰問", "糾問制度", "法官保留原則", "公開審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
